PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE categories (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL UNIQUE,
  slug TEXT NOT NULL UNIQUE,
  description TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE contents (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  title TEXT NOT NULL,
  slug TEXT NOT NULL UNIQUE,
  type TEXT NOT NULL CHECK(type IN ('haber','makale','bildiri','kitap','sempozyum','panel','rapor')),
  category_id INTEGER REFERENCES categories(id),
  summary TEXT NOT NULL,
  full_text TEXT,
  source_name TEXT,
  source_url TEXT,
  image_url TEXT,
  published_at DATE,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
, ai_summarized INTEGER DEFAULT 0, lang TEXT DEFAULT 'tr');
CREATE TABLE tags (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL UNIQUE,
  slug TEXT NOT NULL UNIQUE
);
CREATE TABLE content_tags (
  content_id INTEGER REFERENCES contents(id) ON DELETE CASCADE,
  tag_id INTEGER REFERENCES tags(id) ON DELETE CASCADE,
  PRIMARY KEY (content_id, tag_id)
);
CREATE TABLE scanned_sources (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  url TEXT NOT NULL UNIQUE,
  name TEXT NOT NULL,
  type TEXT NOT NULL DEFAULT 'rss',
  last_scanned DATETIME,
  is_active INTEGER DEFAULT 1
);
CREATE TABLE scan_log (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  source_id INTEGER REFERENCES scanned_sources(id),
  new_items INTEGER DEFAULT 0,
  status TEXT DEFAULT 'success',
  error_msg TEXT,
  scanned_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE INDEX idx_contents_published ON contents(published_at DESC);
CREATE INDEX idx_contents_type ON contents(type);
CREATE INDEX idx_contents_category ON contents(category_id);
COMMIT;
